const Q_CHEMISTRY_1998=[{"id": "objective>Chemistry>1998>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of water to calcium oxide leads to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a physical change</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a chemical change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the formation of a mixture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an endothermic change</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of water to calcium oxide leads to a chemical change. This is because the reaction of calcium oxide (CaO) with water (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O) forms calcium hydroxide (Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), a new substance.</div>", "topic": "CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>1998>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of iron and sulphur can be separated by dissolving the mixture in?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dilute hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dilute sodium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of iron and sulphur can be separated by dissolving the mixture in dilute hydrochloric acid. This is because iron reacts with hydrochloric acid to form iron chloride and hydrogen gas, while sulphur does not react with hydrochloric acid, allowing it to be separated from the iron.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1998>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">8.0 g of an element X react with an excess of copper (ll) tetraoxosulphate (lV) solution to deposit 21.3 g of copper. The correct equation for the reaction is? <br/> (Cu = 64).</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CuSO4<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + XSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + X(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 3Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">8g of element X give 21.3g of copper then the amount of element X that will deposit 1 molecular mass of copper(64g) is x then x =8*64/21.3=24 and the element with mass number 24 is magnesium then the reaction is as follows Mg + CuSO4 = Cu + MgSO4. <br/>  <br/> 8g of X element deposits 21.3g of copper <br/> xg of X element deposits 64g of copper <br/> Therefore x = 64×8/21.3 <br/> x = 24g</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1998>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 50<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>. Form the equation above the volume of oxygen at s.t.p. required to burn 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of propane is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">250 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C3H8 + 502 → 4H2O + 3CO2. <br/> From the equation above 1 mole of propane require 5 moles of oxygen at s.t.p. i.e 22400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of propane is burnt by 5 * 22400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen. <br/>  <br/> ∴ 50cm3 of C3H8 will be burnt by = 50  x 5 =250 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1998>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen was collected over water at 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C and 780 mm Hg. If the vapour pressure of water at the temperature of the experiment was 10 mm Hg, calculate the volume of the gas at 760 mm Hg and 7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">°</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 35.7 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.4 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 25.2 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V1 = 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> T1 = 27 + 273 = 300K and P1 = (780 - 10)mm Hg i.e the pressure minus the vapour pressure of water <br/> P2 = 760mm Hg and T2 = 7 + 273 = 280K <br/> From (P2V2) / (T2) = (P1V1) / (T1) <br/> (770 x 30) / (300) = (760 x O2) / (280) <br/> V2 = (770 x 30x 280) / (300 x 760) <br/> V2 = 28.4 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1998>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given amount of gas occupies 10.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 4 atm, and 273°C. The number of moles of the gas present is? <br/> (Molar volume of a gas at s.t.p. = 22.4 dm3)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.89 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.90 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.80 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.70 mol</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">PV = nRT(Ideal gas equation) <br/> where P = 4atm <br/> V= 10dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> R=0.082(ideal gas constant) <br/> T=(273<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> + 273)K=546K <br/> n=? <br/> PV=nRT <br/> n=PV/RT <br/> n=4 x 10/0.082 x 546 <br/> n=40/44.772 <br/> n=0.89 mol</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1998>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If sulphur (IV) oxide and methane are released simultaneously at the opposite ends of a narrow tube, the rates of diffusion Rso<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and Rch<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will be in the ratio? <br/>  <br/> (S = 32, O = 16, C = 12, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:4</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R1/R2 =√M2/M1 <br/> Where R1 = rate of diffusion of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/>            R2 = rate of diffusion of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>            M1 = RMM of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/>            M2 = RMM of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Therefore  <br/> R(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)/R(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) = √16/64 <br/>                            = √1/4 <br/>                            = 1/2 <br/>  <br/> R(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)/R(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) = 1:2</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1998>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solid begins to melt when?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constituent particles acquires a greater kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy of vibration of particles of the solid is less than the intermolecular forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constituent particles acquires energy above the average kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy of vibration of particles of the solid equals the intermolecular forces</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solid begins to melt when the energy of vibration of particles of the solid equals the intermolecular forces. This is because melting is a phase transition from a solid to a liquid state, which occurs when the particles in a solid gain enough energy to overcome the intermolecular forces holding them together in a fixed lattice structure. When the vibrational energy equals the intermolecular forces, the particles are able to move more freely, leading to the formation of a liquid.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1998>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represents an atom that can combine with chlorine to form </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a covalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an electrovalent bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hydrogen bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a co-ordinate bond</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above represents an atom that can combine with chlorine to form an electrovalent bond</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1998>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following electron configurations indicates an atom with the highest ionization energy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,8,7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,8,8,1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,8,8,2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,8,8,7</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ionization energy is the energy required to remove the valence electron from an atom.the farther an electron to the nucleus the lower the ionization energy because the electrostatic force of attraction the nucleus has for the electron is small,however the nearer the electron the higher the energy because the nucleus is exerting greater force.The energy required to remove the electron will be high</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1998>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The line observed in the sample hydrogen spectrum are due to emission of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons from the atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy by proton transition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy by electron transition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutron from the atom</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lines observed in the hydrogen spectrum are due to the emission of energy by electron transition. When an electron in a hydrogen atom transitions from a higher energy level to a lower energy level, it emits energy in the form of light. The wavelength of this light corresponds to a specific color in the hydrogen spectrum.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SIMPLE HYDROGEN SPECTRUM"}, {"id": "objective>Chemistry>1998>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an element X of an atomic number Z and mass number Y is irradiated by an intense concentration of neutrons, the relevant nuclear equation is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y - 1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z + 1</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y +1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z + 1</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y +1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z - 1</span>X</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an element X is irradiated by neutrons, a neutron is absorbed by the nucleus of the atom, increasing its mass number by 1 but leaving the atomic number (number of protons) unchanged. This is represented by the nuclear equation <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y +1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>X.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>1998>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The property used in obtaining oxygen and nitrogen industrially from air is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The property used in obtaining oxygen and nitrogen industrially from air is the boiling point. Air is a mixture of gases, primarily nitrogen and oxygen. These gases can be separated by fractional distillation, a process that takes advantage of the differences in their boiling points. Nitrogen, which has a lower boiling point, boils off first and is collected, while oxygen, which has a higher boiling point, remains as a liquid and is collected separately.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1998>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Excess phosphorus was burnt in a gas jar and the residual gas passed successively over concentrated KOH solution and concentration H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> before being collected in a flask. The gases collected are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide, nitrogen and the rare gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen and the rare gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide, nitrogen (IV) oxide and the rare gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen (IV) oxide and the rare gases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When phosphorus is burnt in air, it forms phosphorus pentoxide (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>). This reacts with water to form phosphoric acid (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>). The remaining gases in the air are nitrogen and the rare gases. Therefore, the gases collected are nitrogen and the rare gases.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1998>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium tetraoxomanganate (VII) is often added to impure water to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> reduce organic impurities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce inorganic impurities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">destroy bacteria and algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove permanent hardness</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium tetraoxomanganate (VII), also known as potassium permanganate, is a strong oxidizing agent. It is often added to impure water to oxidize and kill bacteria and algae, making the water safer to use.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>1998>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil around a battery manufacturing factory is likely to contain a high concentration of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> salts</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Batteries, especially lead-acid batteries, contain lead (Pb). Therefore, the soil around a battery manufacturing factory is likely to contain a high concentration of lead (Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) salts due to contamination.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOIL POLLUTION"}, {"id": "objective>Chemistry>1998>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">90.0g of MgCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> was placed in 50.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water to give a saturated solubility of the salt is 8.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at the same temperature, what is the mass of the salt left undissolved at the given temperature? <br/>  <br/> (Mg = 24, Cl = 35.5)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">52.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">58.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 85.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">88.5g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of MgCl2 = 95g <br/> The solubility of MgCl2 is 8.0/dm3 <br/> 1 dm3 = 1000cm3 <br/> Solubility of g/cm3 <br/> 8 x 95 → 1000cm3 <br/> x → 50 <br/> x = (50)/(1000) x (8 x 95) / (1) = 38g <br/> Mass of the salt left undissolved = 90 - 38 = 52.0g <br/>  <br/> or <br/>  <br/> n=C×V/1000 <br/> n=m/M <br/> m/M=C×V/1000 <br/> m=C×V×M/1000 <br/> M=24+35.5×2=95g <br/> m= 8×50×95/1000 <br/> m=38g <br/> mass of salt left undissolved <br/> m=90-38=52g</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1998>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soap lather is an example of a colloid in which a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquid is dispersed in gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid is dispersed in liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gas is dispersed in liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid is dispersed in liquid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soap lather is just air bubbles in liquid. Soap lather is an example of a colloid in which a gas is dispersed in liquid.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>1998>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pH of a solution obtained by mixing 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 0.1M HCl solution with 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 0.2M solution of NaOH is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.7</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of reaction: <br/> HCl + NaOH → NaCl + H2O <br/> From the equation 1 mol of HCl reacted with 1 mole of NaOH  <br/> Next let's calculate the number of moles of the acid  and base  <br/>  <br/> n(HCl) = CV = 0.1 x 0.1 = 0.01moles <br/>  <br/> n(NaOH) = CV = 0.2 x 0.1 = 0.02moles <br/>  <br/> This implies that out of the 0.02 mol of NaOH present, only 0.01 mole will be consumed by the 0.01 mole of HCl available since from the equation of the reaction 1 mole of HCl reacted with 1 mole of NaOH  <br/>  <br/> Calculating the number of moles of excess NaOH remaining  <br/> n(NaOH) remaining = 0.02 - 0.01 = 0.01 moles <br/>  <br/> Concentration in mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = n/V(dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>) <br/> V(dm3) = 200/1000 <br/>               = 0.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> C = 0.01/0.2 <br/>    = 0.05mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> This means that our resulting solution is 0.05M NaOH, whose [OH-] = 0.05 <br/>  <br/> pOH=-log[OH-] <br/> [OH-] = 0.05 <br/>  <br/> pOH=-log[0.05] <br/>  <br/> POH = 1.3 <br/> pH + pOH =14 <br/> pH + 1.3 =14 <br/> pH =14 - 1.3 = 12.7</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1998>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the conductance of aqueous potassium tetraoxosulphate (VI) solution, the current carriers are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrated ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrated electrons.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the conductance of aqueous solutions, the current carriers are the ions present in the solution. However, in aqueous solutions, these ions are surrounded by water molecules, forming hydrated ions. Therefore, in the conductance of aqueous potassium tetraoxosulphate (VI) solution, the current carriers are the hydrated ions.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>1998>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 0.1 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of tetraoxosulphate (VI) acid would be needed to dissolve 2.86 g of sodium tetraoxocarbonate (IV) decahydrate crystals? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 11H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> From the equation, 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> dissolves 1 mole of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> Molar mass of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O=286g <br/> No of mole of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O=2.86/286=0.01mole <br/> i.e 0.01 mole of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O will be dissolved by 0.1mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>  <br/> Molarity of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> =Mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>/Vol in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  Vol in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>= 0.01/0.1=0.1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>=100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/> </div>", "topic": "ACID BASE AND SALTS : STOICHIOMETRY"}, {"id": "objective>Chemistry>1998>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1.2F of electricity are passed through électrolytic cells containing Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>, and Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> in series. How many moles of each metal would be formed at the cathode of each cell? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.6 mole of Na, 1.2 moles of Cu and 1.2 moles of Al</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 moles of Na, 0.6 mole of cu and 0.4 mole of Al </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 moles of Na, 2.4 moles of Cu and 2.4 moles of Al </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 moles of Na, 2.4 moles of Cu and 3.6 moles of Al</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of moles of a metal formed at the cathode during electrolysis is directly proportional to the amount of electricity passed through the cell. The Faraday's law of electrolysis states that one Faraday (F) of electricity will deposit one mole of a metal that has a valency of one, half a mole of a metal that has a valency of two, and one-third of a mole of a metal that has a valency of three. Therefore, 1.2 F of electricity will deposit 1.2 moles of Na (valency 1), 0.6 mole of Cu (valency 2), and 0.4 mole of Al (valency 3).</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1998>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What mass of gold is deposited during the electrolysis of gold (III) tetraoxosulphate (VI) when a current of 15A is passed for 193 seconds. <br/>  <br/> [Au= 97, F= 96 500C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>] </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.97 g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.34g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.91 g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">19.70g </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Au<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → Au<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> <br/> I = 15A, t=193 <br/> Q=I x t <br/> Q=15 x 193=2895 <br/> RAM of Au=197 <br/> 3F=3 x 96500 <br/>  <br/> M/RAM=Q/CF <br/> M=Q x RAM/CF <br/> M=2895 x 197/3 x 96500 <br/> M= 570315/289500 <br/> M=1.97g </div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1998>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> → Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>.From the reaction, it can be inferred that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe is the oxidizing agent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe is reduced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> loses electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is the oxidizing agent.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is the oxidizing agent.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1998>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. The reducing agent in the reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is getting oxidized to FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> by losing electrons. Hence, FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is the reducing agent.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>1998>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction that is accompanied by a decrease in entropy when carried out at constant temperature is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> ⇌ CaO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> ⇌ 3N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> is accompanied by a decrease in entropy because it involves the conversion of 4 moles of gaseous reactants into 2 moles of gaseous products. This leads to a decrease in randomness or disorder, hence a decrease in entropy.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>1998>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">32g of anhydrous copper (II) tetraoxosulphate (VI) dissolved in 1 dm³ of water generated 13.0 kJ of heat. The heat of solution is <br/> [Cu = 64, S = 32, O=16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">26.0 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">65.0 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">130.0 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">260.0 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">32g of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> liberate 13.0KJ of heat <br/> Moar mass of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> =160g. <br/> No of mole of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> =32 <br/> No of mole=mass/Molar mass=32/160=0.2mole <br/> i.e 0.2 mole of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will liberate 13.0KJ of heat <br/> ∴ 1 mole of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>  will liberate 13.0KJ/0.2=65KJ </div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1998>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> + 2e-<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Mg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>E°(volts) = -2.370 <br/>  <br/> Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e-<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>E°(volts) = -0.763 <br/>  <br/> Cd<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e-<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Cd<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>E°(volts) = -0.403 <br/>  <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> + 2e-((aq)) → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>E°(volts) = +0.340 <br/>  <br/> In the electrochemical series above, the strongest reducing agents is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cd<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrochemical series, the substance with the most negative standard reduction potential is the strongest reducing agent. Hence, Mg(s) with E° = -2.370 volts is the strongest reducing agent.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1998>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above , the activation energy for the backward reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+5kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+15KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+25KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+30KJ</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the backward reaction, the activation energy = 40kJ - 15kJ = +25kJ</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>1998>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → Z<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>: In the equation above, The rate of formation of Z is found to be independent of the concentration of Y and to quadruple when the concentration of X is doubled. The correct equation for the reaction is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">R=K[X][Y]</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R=K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[Y] <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">R=K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>[Y]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">R=K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[Y]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of formation of Z is independent of the concentration of Y and quadruples when the concentration of X is doubled. This implies that the reaction is first order with respect to X and zero order with respect to Y. Hence, the rate equation is R=K[X]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>[Y]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>1998>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> 4HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> ∆H° = +115KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. In the above equilibrium reaction, a decrease in temperature will?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">favour the reverse reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">favour the forward reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have no effect on the equilibrium state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double the rate of the reverse raection</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, if a system at equilibrium is subjected to a change in temperature, the system shifts in the direction that counteracts the change. Since the reaction is endothermic (∆H° = +115KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>), a decrease in temperature will favour the reverse reaction which is exothermic.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1998>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">3CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2NH3<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 3Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span> + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> (i). <br/>  <br/> 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 6HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> (ii). <br/>  <br/> 4NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 6H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> + 2N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> (iii). <br/>  <br/> The reactions represented by the equations above demonstrate the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">basic properties of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic properties of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing properties of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidizing properties of ammonia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In all the given reactions, ammonia (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) is getting oxidized to N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, hence demonstrating the reducing properties of ammonia.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1998>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas that turns a filter paper previously soaked in lead ethanoate solution black is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur (VI) oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen sulphide (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S) turns a filter paper previously soaked in lead ethanoate solution black due to the formation of lead sulphide (PbS).</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>1998>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solution containing chloride ions gives white precipitate with silver trioxonitrate(V) Solution. The precipitate will be insoluble in dilute?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> but soluble in ammonia solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and ammonia solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl but soluble in ammonia solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl and in ammonia solution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solution containing chloride ions gives white precipitate with silver trioxonitrate(V) Solution. The precipitate (AgCl) is insoluble in dilute HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> but soluble in ammonia solution due to the formation of the complex ion [Ag(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1998>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the experiment above, X could be a solution of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxonitrate (V) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium trioxonitrate (lll) and ammonium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead (ll) trioxonitrate (V) and copper turnings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium trioxonitrate (V) and copper turnings</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above is the preparation of nitrogen(I) oxide. The solution is a mixture of sodium trioxonitrate(V) and ammonium chloride.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1998>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxide that remains unchanged when heated in hydrogen is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CuO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ZnO</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc cannot be reduced using hydrogen as it is less reactive it won't displace zinc from ZnO</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1998>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is observed when a solution of iron (III) chloride is mixed with a solution of sodium hydroxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A gas is evolved</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> A deep blue precipitate is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The resultant solution turns green turns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A brown precipitate is formed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a solution of iron (III) chloride is mixed with a solution of sodium hydroxide, a brown precipitate is formed. This is due to the formation of iron (III) hydroxide, which is brown in color.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1998>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The metal that will react with water only in the form of steam to liberate hydrogen gas is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc is the metal that will react with water only in the form of steam to liberate hydrogen gas. This is because zinc is not reactive enough to react with cold or hot water, but it can react with steam to form zinc oxide and hydrogen gas.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1998>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common characteristic shared by iron and aluminium is that both?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are extracted by reduction methods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form only basic oxides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">show oxidation states of +2 and +3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form soluble hydroxides</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A common characteristic shared by iron and aluminium is that both are extracted by reduction methods. This is a process where oxygen is removed from the ore to obtain the metal.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>1998>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alloys are often used in preference to pure metals because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metals are too hard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals are ductile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic properties are improved in alloys</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alloys are a mixture of metals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alloys are often used in preference to pure metals because metallic properties are improved in alloys. Alloys are a mixture of two or more metals, or a metal and a non-metal, and they often have properties that are different to the metals they contain.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>1998>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">&nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbspOH <br/> &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp| <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CHCH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> The IUPAC nomenclature for the above compound is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4-methylpentan-3-ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpentan-3-ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylpentan-3-ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,1-dimethylbutan-2-ol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature for the above compound is 2-methylpentan-3-ol </div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1998>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dehydration of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-OH gives</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>≡ CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH=CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H-C ≡ CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C ≡ C-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dehydration of CH3-CH2-CH2-CH2-OH gives CH3CH=CH-CH3. Dehydration is a chemical reaction that involves the loss of a water molecule from the reacting molecule.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1998>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">nCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> &nbsp  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> &nbsp (initiator)/1500atm, 473K  &nbsp (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)n. <br/> The equation  represents manufacture of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polythene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polystyrene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation represents the manufacture of polythene. The conditions mentioned in the question (1500atm, 473K) are used in the high-pressure process to produce low-density polythene.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>1998>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of hydrocarbon contains 6g of hydrogen. If the molecular weight is 54, the hydrocarbon is an?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkyne</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CxH6 <br/> ∴ CxH6 = 54 <br/> 12x + 6 = 54 <br/> 12x = 54 - 6 <br/> 12x = 48 <br/> x = (48)/(12) <br/> x = 4 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> (butyne)</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1998>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The products obtained when a pure hydrocarbon is burnt in excess oxygen are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon and hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (II) oxide and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide and water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The products obtained when a pure hydrocarbon is burnt in excess oxygen are carbon (IV) oxide and water. This is a combustion reaction where hydrocarbons react with oxygen to produce carbon dioxide and water.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1998>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many structural isomers can be drawn for the non-cyclic alkanol with molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>O?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The non-cyclic alkanol with molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>O can have 4 structural isomers. These are: Butan-1-ol, Butan-2-ol, 2-Methylpropan-1-ol, and 2-Methylpropan-2-ol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1998>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On cracking medicinal paraffin, a gas is evolved which gives a pop sound with a lighted splinter and an oily liquid which decolourizes bromine solution is also obtained. The products of the cracking are ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> carbon (IV) oxide and alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (ll) oxide and alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen gas and alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen gas and alkane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cracking is a process where long chain hydrocarbons are broken down into smaller, more useful hydrocarbons. The gas evolved which gives a pop sound with a lighted splinter is hydrogen gas and the oily liquid which decolourizes bromine solution is an alkene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1998>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of aromatic compound is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">13</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">13</span>Cl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aromatic compounds are compounds that contain a benzene ring or have certain benzene-like properties. In the given options, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH, also known as phenol, is an aromatic compound.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1998>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Terylene is synthesized from ethane- 1, 2-diol and benzene - 1, 4-dicarboxylic acid by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">addition reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elimination reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitution reaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Terylene is synthesized from ethane- 1, 2-diol and benzene - 1, 4-dicarboxylic acid by a condensation reaction. In a condensation reaction, two molecules combine to form a larger molecule, usually with the loss of a small molecule such as water.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>1998>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true concerning the properties of benzene and hexane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both undergo substitution reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both undergo addition reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both are solids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both can decolourized bromine water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both benzene and hexane undergo substitution reactions. A substitution reaction is a chemical reaction during which one functional group in a chemical compound is replaced by another functional group.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}];
